import React, { useState, useEffect, useCallback } from 'react';
import Select from 'react-select';
import './PurchaseFunc.css';
import AddMaterial from './AddMaterial.js';
import AddVendor from './AddVendor.js';

const AddPurchase = ({ handleAdd, locations, materials, setMaterials, vendors, setVendors, apiBaseUrl }) => {
  const [showAddMaterialForm, setShowAddMaterialForm] = useState(false);
  const [showAddVendorForm, setShowAddVendorForm] = useState(false);

  const openAddMaterialForm = () => {
    setShowAddMaterialForm(true);
  };

  const openAddVendorForm = () => {
    setShowAddVendorForm(true);
  };

  const initialPurchaseState = {
    location: '',
    materialid: '',
    materialname: '',
    quantity: '',
    price: '',
    vendor: '',
    vendorname: '',
    width: null,
    lotnumber: '',
    comments: '',
    invdate: '',
  };

  const [newPurchase, setNewPurchase] = useState(initialPurchaseState);
  const [showExtras, setShowExtras] = useState(false);
  const [materialInputType, setMaterialInputType] = useState('id'); // State to track input type (id or name)
  const [materialNameInput, setMaterialNameInput] = useState(''); // State to store Material Name input
  const [suggestedMaterials, setSuggestedMaterials] = useState([]); // State to store suggested Material IDs

  useEffect(() => {
    const fetchData = async () => {
      const authToken = sessionStorage.getItem('authToken');

      const fetchWithAuth = async (url, options = {}) => {
        return fetch(url, {
          ...options,
          headers: {
            ...options.headers,
            'Authorization': `Bearer ${authToken}`,
          },
        });
      };

      try {
        if (newPurchase.materialid) {
          try {
            const [responseChanges, responseList] = await Promise.all([
              fetchWithAuth(`${apiBaseUrl}/materialchangesAPI/${newPurchase.materialid}`),
              fetchWithAuth(`${apiBaseUrl}/materiallist/${newPurchase.materialid}`),
            ]);

            const [dataChanges, dataList] = await Promise.all([
              responseChanges.json(),
              responseList.json(),
            ]);

            if (dataList && dataList.extras === 1) {
              setShowExtras(true);
            } else {
              setShowExtras(false);
            }

            if (dataChanges && dataChanges.price && dataChanges.vendor) {
              setNewPurchase((prevPurchase) => ({
                ...prevPurchase,
                price: dataChanges.price,
                vendor: dataChanges.vendor,
                vendorname: vendors.find((vendor) => vendor.vendorid === dataChanges.vendor)?.name,
              }));
            } else {
              setNewPurchase((prevPurchase) => ({
                ...prevPurchase,
                price: '',
                vendor: '',
                vendorname: '',
              }));
            }

            setNewPurchase((prevPurchase) => ({
              ...prevPurchase,
              materialname: dataList && dataList.name ? dataList.name : '',
            }));
          } catch (error) {
            console.error('Error fetching material data:', error);
          }
        } else {
          setShowExtras(false);
          setNewPurchase((prevPurchase) => ({
            ...prevPurchase,
            price: '',
            vendor: '',
            vendorname: '',
            materialname: '',
          }));
        }
      } catch (error) {
        console.error('Error fetching data:', error);
      }
    };

    fetchData();
  }, [newPurchase.materialid, vendors, apiBaseUrl]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setNewPurchase((prevPurchase) => ({
      ...prevPurchase,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const authToken = sessionStorage.getItem('authToken');

    const fetchWithAuth = async (url, options = {}) => {
      return fetch(url, {
        ...options,
        headers: {
          ...options.headers,
          'Authorization': `Bearer ${authToken}`,
        },
      });
    };

    try {
      const responseChanges = await fetchWithAuth(`${apiBaseUrl}/materialchangesAPI/${newPurchase.materialid}`);
      const dataChanges = await responseChanges.json();

      const hasChanges =
        dataChanges &&
        (dataChanges.price !== newPurchase.price ||
          dataChanges.vendor !== newPurchase.vendor);

      if (dataChanges && hasChanges) {
        const response = await fetchWithAuth(`${apiBaseUrl}/materialchangesAPI/`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            material_id: newPurchase.materialid,
            price: newPurchase.price,
            vendor: newPurchase.vendor,
          }),
        });

        if (!response.ok) {
          console.error('Failed to create material change:', response);
          return;
        }
      }

      handleAdd(newPurchase);
      setNewPurchase(initialPurchaseState);
    } catch (error) {
      console.error('Error handling the form submission:', error);
    }
  };

  const handleAddMat = useCallback((newMaterial) => {
    const authToken = sessionStorage.getItem('authToken');

    const fetchWithAuth = async (url, options = {}) => {
      return fetch(url, {
        ...options,
        headers: {
          ...options.headers,
          'Authorization': `Bearer ${authToken}`,
        },
      });
    };

    const materialExists = materials.some(
      (material) => material.matid === newMaterial.matid || material.name === newMaterial.name
    );
    if (materialExists) {
      alert('Material ID or name already exists.');
      return;
    }

    fetchWithAuth(`${apiBaseUrl}/materiallist`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(newMaterial),
    })
      .then((response) => {
        if (response.ok) {
          return response.json();
        } else {
          throw new Error('Error adding material');
        }
      })
      .then((data) => {
        setMaterials([...materials, newMaterial]);
        setShowAddMaterialForm(false);
      })
      .catch((error) => {
        console.log('Error adding material:', error);
      });
  }, [materials, setMaterials, setShowAddMaterialForm, apiBaseUrl]);

  const handleAddVendor = useCallback(async (newVendor) => {
    const authToken = sessionStorage.getItem('authToken');

    const fetchWithAuth = async (url, options = {}) => {
      return fetch(url, {
        ...options,
        headers: {
          ...options.headers,
          'Authorization': `Bearer ${authToken}`,
        },
      });
    };

    try {
      // Send an HTTP request to add the new vendor
      const addResponse = await fetchWithAuth(`${apiBaseUrl}/vendors`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(newVendor),
      });

      if (!addResponse.ok) {
        throw new Error('Error adding vendor');
      }

      // Fetch the updated list of vendors from '/vendorsAPI'
      const response = await fetchWithAuth(`${apiBaseUrl}/vendors`);

      if (!response.ok) {
        throw new Error('Failed to fetch vendors');
      }

      const data = await response.json();
      setVendors(data); // Assuming 'setVendors' is a state updater function
      setShowAddVendorForm(false);
    } catch (error) {
      console.error('Error handling the form submission:', error);
    }
  }, [setVendors, setShowAddVendorForm, apiBaseUrl]);

  const handleMaterialInputChangeType = (inputType) => {
    // Update the material input type (id or name)
    setMaterialInputType(inputType);
    setMaterialNameInput('');
  };

  const handleMaterialInputChange = (inputValue) => {
    // Handle material input based on input type (id or name)
    if (materialInputType === 'id') {
      setNewPurchase((prevPurchase) => ({
        ...prevPurchase,
        materialid: inputValue,
      }));
    } else if (materialInputType === 'name') {
      setMaterialNameInput(inputValue);
    }
  };

  const handleSelectMaterial = (selectedOption) => {
    // Handle material selection from the autocomplete dropdown
    const selectedMaterialId = selectedOption.value;

    // Fetch additional material information based on the selected material ID
    fetchWithAuth(`${apiBaseUrl}/materiallist/${selectedMaterialId}`)
      .then((response) => response.json())
      .then((data) => {
        // Update the materialid, materialname, and other relevant fields
        setNewPurchase((prevPurchase) => ({
          ...prevPurchase,
          materialid: selectedMaterialId,
          materialname: data.name || '',
          // Update other fields as needed
        }));
      })
      .catch((error) => {
        console.error('Error fetching material data:', error);
      });
  };

  // Determine whether to disable the Material ID or Material Name input field
  const isMaterialIdDisabled = materialInputType === 'name';
  const isMaterialNameDisabled = materialInputType === 'id';

  return (
    <div className='container'>
      <div>
        <h2 className="heading">Add Purchase</h2>
      </div>
      <form onSubmit={handleSubmit} className="form">
        <div className="form-row">
          <div className="form-group">
            <label>Location:</label>
            <select name="location" value={newPurchase.location} onChange={handleChange} required>
              <option value="">Select a location</option>
              {locations.map((location) => (
                <option key={location.id} value={location.id}>
                  {location.locationname}
                </option>
              ))}
            </select>
          </div>
          <div className="form-group">
            <label>Material Input Type:</label>
            <div className="material-input-type">
              <button
                type="button"
                onClick={() => handleMaterialInputChangeType('id')}
                className={materialInputType === 'id' ? 'active' : ''}
              >
                Material ID
              </button>
              <button
                type="button"
                onClick={() => handleMaterialInputChangeType('name')}
                className={materialInputType === 'name' ? 'active' : ''}
              >
                Material Name
              </button>
            </div>
          </div>
          <div className="form-group">
            <label>
              {materialInputType === 'id' ? 'Material ID:' : 'Material Name:'}
            </label>
            {materialInputType === 'id' ? (
              <input
                type="text"
                name="materialid"
                value={newPurchase.materialid}
                onChange={(e) => handleMaterialInputChange(e.target.value)}
                required
                disabled={isMaterialIdDisabled}
              />
            ) : (
              <input
                type="text"
                name="materialname"
                value={materialNameInput}
                onChange={(e) => handleMaterialInputChange(e.target.value)}
                required
                disabled={isMaterialNameDisabled}
              />
            )}
          </div>
          {/* ... (existing form fields) */}
          {suggestedMaterials.length > 0 && (
            <div className="form-group">
              <label>Suggested Material IDs:</label>
              <Select
                name="suggestedMaterialId"
                options={suggestedMaterials.map((materialId) => ({
                  value: materialId,
                  label: materialId,
                }))}
                onChange={handleSelectMaterial}
                placeholder="Select a Material ID"
                isSearchable
                className="select-field"
              />
            </div>
          )}
          {/* ... (existing form fields) */}
          <div className="form-group">
            <label>Quantity:</label>
            <input type="text" name="quantity" value={newPurchase.quantity} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label>Price:</label>
            <input
              type="text"
              name="price"
              value={newPurchase.price || ''}
              onChange={handleChange}
              required
            />
          </div>
          <div className="form-group">
            <label>Vendor:<span className="add-icon" onClick={openAddVendorForm}>
              +
            </span></label>
            <Select
              name="vendor"
              value={newPurchase.vendor ? { value: newPurchase.vendor, label: vendors.find((ven) => ven.vendorid === newPurchase.vendor)?.name } : null}
              options={vendors.map((vendor) => ({
                value: parseInt(vendor.vendorid),
                label: vendor.name,
              }))}
              onChange={(selectedOption) =>
                handleChange({ target: { name: 'vendor', value: selectedOption.value, vendorname: selectedOption.label } })
              }
              placeholder="Select a Vendor"
              isSearchable
              required
              className="select-field"
            />
          </div>
          <div className='form-group'>
          <label>
            Comments:
            <textarea type="text" name="comments" value={newPurchase.comments} onChange={handleChange} />
          </label>
        </div>
          <button type="submit" className="add_btn">
            Add Purchase
          </button>
        </div>
      </form>
      {showAddMaterialForm && (
        <div className="overlay">
          <div className="popup">
            <span className="close-popup" onClick={() => setShowAddMaterialForm(false)}>
              &times;
            </span>
            <AddMaterial handleAdd={handleAddMat} />
          </div>
        </div>
      )}

      {showAddVendorForm && (
        <div className="overlay">
          <div className="popup">
            <span className="close-popup" onClick={() => setShowAddVendorForm(false)}>
              &times;
            </span>
            <AddVendor handleAddVendor={handleAddVendor} />
          </div>
        </div>
      )}

    </div>
  );
};

export default AddPurchase;
